import { Badge } from './badge';
import { Bot, Calendar, Sparkles, Repeat } from 'lucide-react';
import { useLanguage } from '@/hooks/use-language';
import { cn } from '@/lib/utils';

interface AutoGeneratedBadgeProps {
  label?: string;
  sourceTemplate?: string;
  generationDate?: string;
  variant?: 'default' | 'compact' | 'detailed';
  className?: string;
}

export function AutoGeneratedBadge({ 
  label, 
  sourceTemplate, 
  generationDate,
  variant = 'default',
  className 
}: AutoGeneratedBadgeProps) {
  const { t } = useLanguage();

  // Enhanced styling for auto-generated bills
  const badgeClass = cn(
    "gap-1 border-blue-200 bg-blue-50 text-blue-700 hover:bg-blue-100",
    "dark:border-blue-800 dark:bg-blue-950/50 dark:text-blue-300 dark:hover:bg-blue-900/50",
    variant === 'compact' && "text-xs px-2 py-1",
    variant === 'detailed' && "text-sm px-3 py-1.5",
    variant === 'default' && "text-xs",
    className
  );

  if (variant === 'detailed' && sourceTemplate) {
    return (
      <div className="flex flex-col gap-1">
        <Badge 
          className={badgeClass}
          data-testid="badge-auto-generated-detailed"
        >
          <Sparkles className="h-3 w-3" />
          Auto-Generated
        </Badge>
        <div className="text-xs text-muted-foreground flex items-center gap-1">
          <Repeat className="h-3 w-3" />
          From: {sourceTemplate}
        </div>
        {generationDate && (
          <div className="text-xs text-muted-foreground flex items-center gap-1">
            <Calendar className="h-3 w-3" />
            Generated: {new Date(generationDate).toLocaleDateString()}
          </div>
        )}
      </div>
    );
  }

  if (variant === 'compact') {
    return (
      <Badge 
        className={badgeClass}
        data-testid="badge-auto-generated-compact"
        title={sourceTemplate ? `Auto-generated from: ${sourceTemplate}` : 'Auto-generated bill'}
      >
        <Bot className="h-3 w-3" />
        Auto
      </Badge>
    );
  }

  return (
    <Badge 
      className={badgeClass}
      data-testid="badge-auto-generated"
      title={sourceTemplate ? `Auto-generated from: ${sourceTemplate}` : 'Auto-generated bill'}
    >
      <Bot className="h-3 w-3" />
      {label || 'Auto-Generated'}
    </Badge>
  );
}